urlset:

  {{ '/' | absurl }}


  {{ '/photography/' | absurl }}

{% for gallery in galleries %}
{% if gallery.listed %}

  {{ ('/photography/' + gallery.slug + '/') | absurl }}

{% endif %}
{% for photo in gallery.photos %}

  {{ ('/photography/' + gallery.slug + '/' + photo.slug + '/') | absurl }}

{% endfor %}
{% endfor %}

  {{ '/blog/' | absurl }}

{% for post in posts %}

  {{ ('/blog/' + post.slug + '/') | absurl }}

{% endfor %}
{% for page in pages %}

  {{ ('/' + page.slug + '/') | absurl }}

{% endfor %}
